import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjStreamList } from "./OjStreamList";
export { OjStreamList };

/**
 * Create an instance of [[OjStreamList]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojStreamList(driver, By.id('my-oj-stream-list'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojStreamList(driver: DriverLike, by: By): Promise<OjStreamList> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjStreamList
  if (!(webEl instanceof OjStreamList)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-stream-list>`);
  }
  return webEl;
}

register("oj-stream-list", OjStreamList);
